| Control UI Store | Source Path | Cockpit Wrapper | Action |
|-----------------|-------------|-----------------|--------|
| `useGatewayStore` | `ui/src/stores/gateway.ts` | `useCockpitGatewayStore` | Re-export + oklch status |
| `useConfigStore` | `ui/src/stores/config.ts` | `useCockpitConfigStore` | Re-export + theme-aware |
| `useCronStore` | `ui/src/stores/cron.ts` | `useCockpitCronStore` | Re-export + oklch badges |
| `useSkillsStore` | `ui/src/stores/skills.ts` | `useCockpitSkillsStore` | Re-export + oklch toggles |
| `useSessionStore` | `ui/src/stores/sessions.ts` | `useCockpitSessionStore` | Re-export + oklch overrides |
| `useChatStore` | `ui/src/stores/chat.ts` | `useCockpitChatStore` | Re-export + message styling |
| `useThemeStore` | `ui/src/stores/theme.ts` | `useCockpitThemeStore` | Map to oklch modes |

### 6.2 Wrapper Pattern

```typescript
// lib/stores/cockpit-gateway.ts
import { useGatewayStore as useBaseGatewayStore } from "@openclaw/ui/stores/gateway";
import { useCockpitTheme } from "./cockpit-theme";

export function useCockpitGatewayStore() {
  const base = useBaseGatewayStore();
  const theme = useCockpitTheme();

  return {
    ...base,
    // Augment with oklch-branded status
    connectionStatus: {
      ...base.connectionStatus,
      indicator: theme.pulse, // "idle" | "streaming" | "error" | "offline"
      hue: theme.hue,
    },
  };
}
```

