// Stub gateway client for Cockpit — will be replaced with real Control UI source consumption
import { useEffect, useRef, useState, useCallback } from "react";

export type GatewayStatus = "idle" | "connecting" | "connected" | "error" | "disconnected";

export type GatewayRequestError = {
  message: string;
  code?: string;
  details?: unknown;
};

export interface GatewayBrowserClient {
  connect: () => void;
  disconnect: () => void;
  request: <T>(method: string, params?: unknown) => Promise<T>;
  onEvent: (handler: (event: unknown) => void) => () => void;
}

class GatewayBrowserClientImpl implements GatewayBrowserClient {
  private ws: WebSocket | null = null;
  private url: string;
  private token?: string;
  private password?: string;
  private eventHandlers: Set<(event: unknown) => void> = new Set();
  private requestId = 0;
  private pendingRequests = new Map<
    number,
    { resolve: (value: unknown) => void; reject: (reason: unknown) => void }
  >();

  constructor(params: { url: string; token?: string; password?: string }) {
    this.url = params.url;
    this.token = params.token;
    this.password = params.password;
  }

  connect() {
    if (this.ws?.readyState === WebSocket.OPEN) return;

    const url = new URL(this.url);
    if (this.token) {
      url.searchParams.set("token", this.token);
    }
    if (this.password) {
      url.searchParams.set("password", this.password);
    }

    this.ws = new WebSocket(url.toString());

    this.ws.onopen = () => {
      this.eventHandlers.forEach((h) => h({ type: "connected" }));
    };

    this.ws.onmessage = (msg) => {
      try {
        const data = JSON.parse(msg.data);
        if (data.id !== undefined && this.pendingRequests.has(data.id)) {
          const req = this.pendingRequests.get(data.id)!;
          this.pendingRequests.delete(data.id);
          if (data.error) {
            req.reject(data.error);
          } else {
            req.resolve(data.result);
          }
        } else if (data.event) {
          this.eventHandlers.forEach((h) => h(data));
        }
      } catch {
        // ignore
      }
    };

    this.ws.onclose = () => {
      this.eventHandlers.forEach((h) => h({ type: "disconnected" }));
    };

    this.ws.onerror = (err) => {
      this.eventHandlers.forEach((h) => h({ type: "error", error: err }));
    };
  }

  disconnect() {
    this.ws?.close();
    this.ws = null;
  }

  request<T>(method: string, params?: unknown): Promise<T> {
    return new Promise((resolve, reject) => {
      if (!this.ws || this.ws.readyState !== WebSocket.OPEN) {
        reject(new Error("Gateway not connected"));
        return;
      }
      const id = ++this.requestId;
      this.pendingRequests.set(id, { resolve: resolve as (value: unknown) => void, reject });
      this.ws.send(JSON.stringify({ id, method, params }));
    });
  }

  onEvent(handler: (event: unknown) => void) {
    this.eventHandlers.add(handler);
    return () => this.eventHandlers.delete(handler);
  }
}

export function useGatewayClient() {
  const [status, setStatus] = useState<GatewayStatus>("idle");
  const clientRef = useRef<GatewayBrowserClientImpl | null>(null);

  const connect = useCallback(() => {
    if (!clientRef.current) {
      clientRef.current = new GatewayBrowserClientImpl({
        url: "ws://localhost:18790/gateway",
      });
    }
    clientRef.current.connect();
    setStatus("connecting");

    const unsub = clientRef.current.onEvent((evt) => {
      if ((evt as { type: string }).type === "connected") setStatus("connected");
      if ((evt as { type: string }).type === "disconnected") setStatus("disconnected");
      if ((evt as { type: string }).type === "error") setStatus("error");
    });

    return () => unsub();
  }, []);

  const disconnect = useCallback(() => {
    clientRef.current?.disconnect();
    setStatus("idle");
  }, []);

  const request = useCallback(
    async <T,>(method: string, params?: unknown): Promise<T> => {
      if (!clientRef.current) throw new Error("Client not initialized");
      return clientRef.current.request<T>(method, params);
    },
    [],
  );

  useEffect(() => {
    return () => {
      clientRef.current?.disconnect();
    };
  }, []);

  return {
    status,
    client: clientRef.current,
    connect,
    disconnect,
    request,
  };
}

export { GatewayBrowserClientImpl as GatewayBrowserClient };

